namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dMinTanhTanhCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    if (x_shape->GetDimNum() != 4 || w_shape->GetDimNum() != 4) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t n   = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t cin = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t hin = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t win = static_cast<uint32_t>(x_shape->GetDim(3));

    const uint32_t cout = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t wcin = static_cast<uint32_t>(w_shape->GetDim(1));
    const uint32_t kh   = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t kw   = static_cast<uint32_t>(w_shape->GetDim(3));

    if (cin != wcin) return ge::GRAPH_FAILED;
    if (hin < kh || win < kw) return ge::GRAPH_FAILED;

    const uint32_t hout = hin - kh + 1u; // stride=1, pad=0, dil=1
    const uint32_t wout = win - kw + 1u;

    const uint64_t totalPos64 = static_cast<uint64_t>(n) * static_cast<uint64_t>(hout) * static_cast<uint64_t>(wout);
    if (totalPos64 == 0ull) return ge::GRAPH_FAILED;
    const uint32_t totalPos = static_cast<uint32_t>(totalPos64);

    // Optional bias presence
    uint32_t hasBias = 0u;
    if (context->GetInputsSize() >= 3) {
        const gert::Shape *b_shape = context->GetInputShape(2);
        if (b_shape != nullptr && b_shape->GetDimNum() == 1 && static_cast<uint32_t>(b_shape->GetDim(0)) == cout) {
            hasBias = 1u;
        }
    }

    // Conservative blockDim selection
    uint32_t blockDim = totalPos;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_n(n);
    tiling.set_cin(cin);
    tiling.set_hin(hin);
    tiling.set_win(win);
    tiling.set_cout(cout);
    tiling.set_kh(kh);
    tiling.set_kw(kw);
    tiling.set_hout(hout);
    tiling.set_wout(wout);
    tiling.set_totalPos(totalPos);
    tiling.set_hasBias(hasBias);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaces = context->GetWorkspaceSizes(1);
    workspaces[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

