static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x = context->GetInputShape(0);
    const gert::Shape *w = context->GetInputShape(1);

    if (x->GetDimNum() != 4 || w->GetDimNum() != 4) {
        return GRAPH_FAILED;
    }

    int64_t n   = x->GetDim(0);
    int64_t cin = x->GetDim(1);
    int64_t hin = x->GetDim(2);
    int64_t win = x->GetDim(3);

    int64_t cout = w->GetDim(0);
    int64_t wcin = w->GetDim(1);
    int64_t kh   = w->GetDim(2);
    int64_t kw   = w->GetDim(3);

    if (cin != wcin) return GRAPH_FAILED;
    if (hin < kh || win < kw) return GRAPH_FAILED;

    int64_t hout = hin - kh + 1;
    int64_t wout = win - kw + 1;

    gert::Shape *y = context->GetOutputShape(0);
    y->SetDimNum(4);
    y->SetDim(0, n);
    y->SetDim(1, 1);
    y->SetDim(2, hout);
    y->SetDim(3, wout);
