#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv2d_min_tanh_tanh_impl_npu(const at::Tensor& x,
                                         const at::Tensor& weight,
                                         c10::optional<at::Tensor> conv_bias_opt)
{
    at::Tensor out;
    // Output shape: [N, 1, H-Kh+1, W-Kw+1]
    auto N = x.size(0);
    auto H = x.size(2);
    auto W = x.size(3);
    auto Kh = weight.size(2);
    auto Kw = weight.size(3);
    auto Hout = H - Kh + 1;
    auto Wout = W - Kw + 1;
    out = at::empty({N, 1, Hout, Wout}, x.options());

    at::Tensor bias = conv_bias_opt.has_value() ? conv_bias_opt.value() : at::Tensor();
    EXEC_NPU_CMD(aclnnConv2dMinTanhTanhCustom, x, weight, bias, out);
    return out;
}

